import React, { useContext } from 'react'
import { ShopContext } from '../context/Shopcontextprovider';
import all_product from '../component/Assets/all_product';
import remove_icon from "../component/Assets/cart_cross_icon.png";
import "./Cart.css";
export default function Cart() {
    const { cartItem, removeFromCart } = useContext(ShopContext);
    // console.log(cartItem);
    const hasItems = all_product.some(
        (product) => cartItem[product.id]?.quantity > 0
    );
    let subtotal = 0;
    all_product.forEach((product) => {
        subtotal += product.new_price * (cartItem[product.id]?.quantity || 0);
    })
    return (
        <div style={{ marginTop: "50px" }}>
            {
                hasItems && (
                    <>
                        <table
                            style={{
                                width: "90%",
                                margin: "auto",
                                borderCollapse: "collapse"
                            }}
                        >
                            <thead>
                                <tr
                                    style={{
                                        borderBottom: "1px solid #e2e2e2",
                                        textAlign: "left"
                                    }}
                                >
                                    <th>Product</th>
                                    <th style={{ width: "30%" }}>Title</th>
                                    <th>Price</th>
                                    <th>Quantity</th>
                                    <th>Size</th>
                                    <th>Total</th>
                                    <th>Remove</th>
                                </tr>
                            </thead>
                            <tbody style={{
                                width: "90%",
                                margin: "auto",
                            }}>
                                {all_product.map((product) => {
                                    if (cartItem[product.id]?.quantity) {
                                        return (
                                            <tr
                                                style={{
                                                    borderBottom: "1px solid #e2e2e2"
                                                }}
                                            >
                                                <td>
                                                    <img src={product.image} alt='' width="100px" style={{ marginTop: "20px", marginBottom: "20px" }} />
                                                </td>
                                                <td>
                                                    {product.name}
                                                </td>
                                                <td>
                                                    ${product.new_price}
                                                </td>
                                                <td>
                                                    <div style={{ border: "1px solid black", height: "20px", width: "20px", justifyContent: "center", alignItems: "center", display: "flex" }}>
                                                        {cartItem[product.id]?.quantity}
                                                    </div>
                                                </td>
                                                <td>
                                                    {cartItem[product.id]?.size}
                                                </td>
                                                <td>
                                                    ${product.new_price * cartItem[product.id]?.quantity}
                                                </td>
                                                <td>
                                                    <img src={remove_icon} alt='' width="20px" onClick={() => removeFromCart(product.id)} />
                                                </td>
                                            </tr>
                                        )
                                    }
                                    return null;
                                })
                                }

                            </tbody>

                        </table >
                    </>
                )
            }
            <div className='cart'>
                <div className='payment'>
                    <h1>Cart Totals</h1>
                    <div className='cart-item-total' style={{ borderBottom: "2px solid #e2e2e2" }}>
                        <p>Subtotal</p>
                        <p>${subtotal}</p>
                    </div>
                    <div className='cart-item-total' style={{ borderBottom: "2px solid #e2e2e2" }}>
                        <p>Shipping Fee</p>
                        <p>Free</p>
                    </div>
                    <div className='cart-item-total'>
                        <h3>Total</h3>
                        <h3>${subtotal}</h3>
                    </div>
                    <button className='proceed-btn'>PROCEED TO CHCECKOUT</button>
                </div>
                <div className='promoCode'>
                    <p>if you have a promo code, Enter it here.</p>
                    <div className='promo'>
                        <input placeholder='promo code' />
                        <button>Submit</button>
                    </div>
                </div>
            </div>
        </div >
    )
}